import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Decoder — 2026-04-26","description":"","frontmatter":{"title":"The Decoder — 2026-04-26","date":"2026-04-26T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-26-the-decoder.md","filePath":"research/ai-news/2026-04/2026-04-26-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-04/2026-04-26-the-decoder.md"};function n(h,e,c,d,l,i){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🔓-the-decoder-—-2026-04-26" tabindex="-1">🔓 The Decoder — 2026-04-26 <a class="header-anchor" href="#🔓-the-decoder-—-2026-04-26" aria-label="Permalink to &quot;🔓 The Decoder — 2026-04-26&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="gpt-5-5-tops-benchmarks-but-still-hallucinates-frequently-and-costs-20-percent-more-over-the-api" tabindex="-1"><a href="https://the-decoder.com/gpt-5-5-tops-benchmarks-but-still-hallucinates-frequently-and-costs-20-percent-more-over-the-api/" target="_blank" rel="noreferrer">GPT-5.5 tops benchmarks but still hallucinates frequently and costs 20 percent more over the API</a> <a class="header-anchor" href="#gpt-5-5-tops-benchmarks-but-still-hallucinates-frequently-and-costs-20-percent-more-over-the-api" aria-label="Permalink to &quot;[GPT-5.5 tops benchmarks but still hallucinates frequently and costs 20 percent more over the API](https://the-decoder.com/gpt-5-5-tops-benchmarks-but-still-hallucinates-frequently-and-costs-20-percent-more-over-the-api/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-04-25</em></p><p>GPT-5.5 pushes OpenAI back to the top of the AI benchmarks. The price went up, but it still looks like the best bang for your buck among proprietary models.</p><p>The article <a href="https://the-decoder.com/gpt-5-5-tops-benchmarks-but-still-hallucinates-frequently-and-costs-20-percent-more-over-the-api/" target="_blank" rel="noreferrer">GPT-5.5 tops benchmarks but still hallucinates frequently and costs 20 percent more over the API</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="us-programmer-job-growth-nearly-halved-since-chatgpt-launched-fed-study-finds" tabindex="-1"><a href="https://the-decoder.com/us-programmer-job-growth-nearly-halved-since-chatgpt-launched-fed-study-finds/" target="_blank" rel="noreferrer">US programmer job growth nearly halved since ChatGPT launched, Fed study finds</a> <a class="header-anchor" href="#us-programmer-job-growth-nearly-halved-since-chatgpt-launched-fed-study-finds" aria-label="Permalink to &quot;[US programmer job growth nearly halved since ChatGPT launched, Fed study finds](https://the-decoder.com/us-programmer-job-growth-nearly-halved-since-chatgpt-launched-fed-study-finds/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-04-25</em></p><p>Programmers are among the professional groups whose everyday lives have changed the most as a result of generative AI. A new study by the Federal Reserve Board now provides evidence that this is also reflected in employment figures.</p><p>The article <a href="https://the-decoder.com/us-programmer-job-growth-nearly-halved-since-chatgpt-launched-fed-study-finds/" target="_blank" rel="noreferrer">US programmer job growth nearly halved since ChatGPT launched, Fed study finds</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="qwen3-6-27b-beats-much-larger-predecessor-on-most-coding-benchmarks" tabindex="-1"><a href="https://the-decoder.com/qwen3-6-27b-beats-much-larger-predecessor-on-most-coding-benchmarks/" target="_blank" rel="noreferrer">Qwen3.6-27B beats much larger predecessor on most coding benchmarks</a> <a class="header-anchor" href="#qwen3-6-27b-beats-much-larger-predecessor-on-most-coding-benchmarks" aria-label="Permalink to &quot;[Qwen3.6-27B beats much larger predecessor on most coding benchmarks](https://the-decoder.com/qwen3-6-27b-beats-much-larger-predecessor-on-most-coding-benchmarks/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-04-25</em></p><p>Alibaba&#39;s new open-source model Qwen3.6-27B beats its 15-times-larger predecessor across coding benchmarks with just 27 billion parameters.</p><p>The article <a href="https://the-decoder.com/qwen3-6-27b-beats-much-larger-predecessor-on-most-coding-benchmarks/" target="_blank" rel="noreferrer">Qwen3.6-27B beats much larger predecessor on most coding benchmarks</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-says-stronger-ai-models-cut-better-deals-and-the-losers-don-t-even-notice" tabindex="-1"><a href="https://the-decoder.com/anthropic-says-stronger-ai-models-cut-better-deals-and-the-losers-dont-even-notice/" target="_blank" rel="noreferrer">Anthropic says stronger AI models cut better deals, and the losers don&#39;t even notice</a> <a class="header-anchor" href="#anthropic-says-stronger-ai-models-cut-better-deals-and-the-losers-don-t-even-notice" aria-label="Permalink to &quot;[Anthropic says stronger AI models cut better deals, and the losers don&#39;t even notice](https://the-decoder.com/anthropic-says-stronger-ai-models-cut-better-deals-and-the-losers-dont-even-notice/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-04-25</em></p><p>Anthropic let 69 AI agents trade on behalf of employees in an internal marketplace for a week. Stronger models scored better deals, and the people stuck with weaker agents never noticed. If AI models start handling real transactions for humans, these dynamics could deepen existing economic inequalities.</p><p>The article <a href="https://the-decoder.com/anthropic-says-stronger-ai-models-cut-better-deals-and-the-losers-dont-even-notice/" target="_blank" rel="noreferrer">Anthropic says stronger AI models cut better deals, and the losers don&#39;t even notice</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="the-uae-wants-half-its-government-run-by-autonomous-ai-agents-within-two-years" tabindex="-1"><a href="https://the-decoder.com/the-uae-wants-half-its-government-run-by-autonomous-ai-agents-within-two-years/" target="_blank" rel="noreferrer">The UAE wants half its government run by autonomous AI agents within two years</a> <a class="header-anchor" href="#the-uae-wants-half-its-government-run-by-autonomous-ai-agents-within-two-years" aria-label="Permalink to &quot;[The UAE wants half its government run by autonomous AI agents within two years](https://the-decoder.com/the-uae-wants-half-its-government-run-by-autonomous-ai-agents-within-two-years/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-04-25</em></p><p>The United Arab Emirates plans to shift half of its government operations to autonomous AI systems within two years.</p><p>The article <a href="https://the-decoder.com/the-uae-wants-half-its-government-run-by-autonomous-ai-agents-within-two-years/" target="_blank" rel="noreferrer">The UAE wants half its government run by autonomous AI agents within two years</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const u=t(s,[["render",n]]);export{m as __pageData,u as default};
